package tests;import base.BaseTestPlaywright;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP03CambiarEstadoPreparacionPlaywrightTest extends BaseTestPlaywright {    @Test    void cocineroCambiaEstadoAEnPreparacion() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']").fill("cocinero");        page.locator("input[name='password']").fill("123");        page.locator("button[type='submit']").click();        page.waitForTimeout(2000);        long botonesAntes =                page.locator("button:has-text('Comenzar Preparación')")                        .count();        assertTrue(                botonesAntes > 0,                "No existen pedidos pendientes para la prueba."        );        page.locator("button:has-text('Comenzar Preparación')")                .first()                .click();        page.waitForTimeout(2000);        long botonesDespues =                page.locator("button:has-text('Comenzar Preparación')")                        .count();        assertTrue(                botonesDespues < botonesAntes,                "El pedido no cambió a En Preparación."        );        page.screenshot(                new com.microsoft.playwright.Page.ScreenshotOptions()                        .setPath(Paths.get(                                "evidencias/HP03-pedido-en-preparacion.png"))                        .setFullPage(true)        );    }}